<style scoped lang="scss">
.upload-box {
  display: inline-block;
  border: 1px dashed #c0ccda;
  border-radius: 6px;
  height: 107px;
  width: 308px;
  cursor: pointer;
  overflow: hidden;
}
.setting_pic {
  height: 107px;
  width: 308px;
}
</style>

<template>
  <div>
<!--    <SpPlatformTip />-->
    <el-tabs v-if="$route.path.indexOf('editor') === -1" v-model="activeName" type="card">
      <el-tab-pane label="助力活動管理" name="list">
        <div class="content-bottom-padded">
          <el-button type="primary" icon="el-icon-plus" @click="addBargains">
            新增助力活動
          </el-button>
        </div>
        <el-table v-loading="loading" :data="dataList" :height="wheight - 230">
          <el-table-column prop="title" label="活動名稱" />
          <el-table-column label="活動時間" width="180">
            <template slot-scope="scope">
              {{ scope.row.begin_time | datetime('YYYY-MM-DD HH:mm:ss') }} <br>
              {{ scope.row.end_time | datetime('YYYY-MM-DD HH:mm:ss') }}
            </template>
          </el-table-column>
          <el-table-column prop="item_name" label="產品名稱" />
          <el-table-column label="產品原價" align="center">
            <template slot-scope="scope"> NT${{ scope.row.mkt_price / 100 }} </template>
          </el-table-column>
          <el-table-column label="產品底價" align="center">
            <template slot-scope="scope"> NT${{ scope.row.price / 100 }} </template>
          </el-table-column>
          <!-- <el-table-column label="助力範圍" align="center">
            <template slot-scope="scope">
              NT$[{{scope.row.bargain_range.min / 100}} ~ {{scope.row.bargain_range.max / 100}}]
            </template>
          </el-table-column> -->
          <el-table-column label="助力人數" align="center">
            <template slot-scope="scope">
              {{ scope.row.people_range.min }} ~ {{ scope.row.people_range.max }}
            </template>
          </el-table-column>
          <el-table-column prop="limit_num" label="產品數量" align="center" />
          <el-table-column prop="order_num" label="已購數量" align="center" />
          <el-table-column label="操作">
            <template slot-scope="scope">
              <i
                v-if="!scope.row.is_expired"
                class="iconfont icon-edit1"
                @click="editBargains(scope.$index, scope.row)"
              />
              <i
                v-if="!scope.row.is_expired"
                class="iconfont icon-user-slash"
                @click="terminateBargainsAction(scope.$index, scope.row)"
                >廢除</i
              >
              <i
                class="mark iconfont icon-trash-alt1"
                @click="deleteBargainsAction(scope.$index, scope.row)"
              />
            </template>
          </el-table-column>
        </el-table>
        <div v-if="total_count > params.pageSize" class="content-center content-padded">
          <el-pagination
            layout="prev, pager, next"
            :total="total_count"
            :page-size="params.pageSize"
            @current-change="handleCurrentChange"
          />
        </div>
      </el-tab-pane>
      <el-tab-pane label="助力廣告圖" name="image">
        <el-form ref="form" label-position="left">
          <el-form-item>
            <div class="frm-tips">隻能上傳jpg/png文件，且不超過2M （建議尺寸：617px * 214px）</div>
            <div>
              <div class="upload-box" @click="handleImgChange">
                <img v-if="ad_pic" :src="wximageurl + ad_pic" class="setting_pic">
                <i v-else class="el-icon-plus avatar-uploader-icon" />
              </div>
            </div>
            <imgPicker
              :dialog-visible="imgDialog"
              :sc-status="isGetImage"
              @chooseImg="pickImg"
              @closeImgDialog="closeImgDialog"
            />
          </el-form-item>
        </el-form>
        <div class="section-footer with-border content-center" style="width: 100%">
          <el-button type="primary" @click="saveAdPic"> 保 存 </el-button>
        </div>
      </el-tab-pane>
    </el-tabs>
    <router-view />
  </div>
</template>
<script>
import { mapGetters } from 'vuex'
import imgPicker from '../../../components/imageselect'
import { listBargins, deleteBargains, terminateBargains } from '../../../api/promotions'
import util from '../../../common/js/util'
import { setPageParams, getParamByTempName, updateParamsById } from '../../../api/wxa'
export default {
  provide() {
    return {
      refresh: this.refresh
    }
  },
  components: {
    imgPicker
  },
  data() {
    return {
      isGetImage: false,
      imgDialog: false,
      loading: false,
      ad_pic: '',
      total_count: 0,
      activeName: 'list',
      tempatePageKanJiaParamId: 0,
      submit: false,
      params: {
        page: 1,
        pageSize: 20
      },
      dataList: []
    }
  },
  computed: {
    ...mapGetters(['wheight'])
  },
  mounted() {
    this.getBargainsList()
    // this.getAdPic()
  },
  methods: {
    saveAdPic() {
      if (this.tempatePageKanJiaParamId) {
        let params = { ad_pic: this.ad_pic }
        let query = {
          params: params,
          template_name: 'yykcutdown',
          name: 'banner',
          page_name: 'pages/kanjia',
          id: this.tempatePageKanJiaParamId
        }
        updateParamsById(query).then((response) => {
          // this.getAdPic()
          this.$message({
            message: '儲存成功',
            type: 'success',
            duration: 5 * 1000
          })
        })
      } else {
        if (!this.submit) {
          this.submit = true
          let params = { ad_pic: this.ad_pic }
          let query = {
            params: params,
            template_name: 'yykcutdown',
            name: 'banner',
            page_name: 'pages/kanjia'
          }
          setPageParams(query).then((response) => {
            // this.getAdPic()
            this.submit = false
            this.$message({
              message: '儲存成功',
              type: 'success',
              duration: 5 * 1000
            })
          })
        }
      }
    },
    handleImgChange() {
      this.imgDialog = true
      this.isGetImage = true
    },
    pickImg(data) {
      this.ad_pic = data.url
      this.imgDialog = false
    },
    closeImgDialog() {
      this.imgDialog = false
    },
    addBargains() {
      this.$router.push({ path: this.matchHidePage('editor') })
    },
    editBargains(index, row) {
      this.$router.push({ path: this.matchHidePage('editor/') + row.bargain_id })
    },
    getAdPic() {
      let filter = { template_name: 'yykcutdown', name: 'banner', page_name: 'pages/kanjia' }
      getParamByTempName(filter).then((res) => {
        if (res.data.data) {
          this.ad_pic = res.data.data[0].params.ad_pic
          this.tempatePageKanJiaParamId = res.data.data[0].id
        }
      })
    },
    deleteBargainsAction(index, row) {
      this.$confirm('此操作將刪除該助力活動, 是否繼續?', '提示', {
        confirmButtonText: '確定',
        cancelButtonText: '取消',
        type: 'warning'
      })
        .then(() => {
          deleteBargains(row.bargain_id).then((response) => {
            this.$message({
              message: '刪除助力活動成功',
              type: 'success',
              duration: 5 * 1000
            })
            this.getBargainsList()
          })
        })
        .catch(() => {
          this.$message({
            type: 'info',
            message: '已取消'
          })
        })
    },
    terminateBargainsAction(index, row) {
      this.$confirm('此操作將廢除該助力活動, 是否繼續?', '提示', {
        confirmButtonText: '確定',
        cancelButtonText: '取消',
        type: 'warning'
      })
        .then(() => {
          terminateBargains(row.bargain_id).then((response) => {
            this.$message({
              message: '廢除助力活動成功',
              type: 'success',
              duration: 5 * 1000
            })
            this.getBargainsList()
          })
        })
        .catch(() => {
          this.$message({
            type: 'info',
            message: '已取消'
          })
        })
    },
    getBargainsList() {
      this.loading = true
      let params = { page: this.params.page, pageSize: this.params.pageSize }
      listBargins(params)
        .then((response) => {
          this.loading = false
          this.dataList = response.data.data.list
          this.total_count = response.data.data.total_count
        })
        .catch((error) => {
          this.$message({
            type: 'error',
            message: '獲取活動列表出錯'
          })
        })
    },
    handleCurrentChange(page_num) {
      this.params.page = page_num
      this.getBargainsList()
    },
    refresh() {
      this.getBargainsList()
      // this.getAdPic()
    }
  }
}
</script>
